import React, { useRef, useEffect } from "react";
import { motion } from "framer-motion";
import { SectionLabel, sectionTitle } from "./Skills";

export default function Contact({ contact }) {
  const sectionRef = useRef(null);

  const items = [
    { icon: "✉", label: "Email", value: contact.email, href: `mailto:${contact.email}`, copy: true },
    { icon: "📞", label: "Phone", value: contact.phone, href: `tel:${contact.phone}` },
    { icon: "in", label: "LinkedIn", value: contact.linkedin, href: contact.linkedinUrl },
    { icon: "📍", label: "Location", value: contact.location, href: null },
  ];

  /* 📋 Copy Email */
  const handleCopy = (text) => {
    navigator.clipboard.writeText(text);
  };

  /* 🧲 Magnetic Effect */
  const handleMouseMove = (e, ref) => {
    const rect = ref.current.getBoundingClientRect();
    const x = e.clientX - rect.left - rect.width / 2;
    const y = e.clientY - rect.top - rect.height / 2;
    ref.current.style.transform = `translate(${x * 0.1}px, ${y * 0.1}px)`;
  };

  const resetMagnet = (ref) => {
    ref.current.style.transform = "translate(0,0)";
  };

  /* 🖱️ Cursor Glow */
  useEffect(() => {
    const glow = document.createElement("div");
    glow.className = "cursor-glow";
    document.body.appendChild(glow);

    const move = (e) => {
      glow.style.left = e.clientX + "px";
      glow.style.top = e.clientY + "px";
    };

    window.addEventListener("mousemove", move);

    return () => {
      window.removeEventListener("mousemove", move);
      document.body.removeChild(glow);
    };
  }, []);

  /* 🎬 Animations */
  const container = {
    hidden: {},
    show: { transition: { staggerChildren: 0.12 } },
  };

  const fadeUp = {
    hidden: { opacity: 0, y: 40 },
    show: { opacity: 1, y: 0, transition: { duration: 0.6 } },
  };

  return (
    <>
      <style>{`
        .contact-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1.25rem, 5vw, 4rem);
          text-align: center;
          position: relative;
        }

        /* 🖱️ Cursor Glow */
        .cursor-glow {
          position: fixed;
          width: 300px;
          height: 300px;
          background: radial-gradient(circle, rgba(0,229,255,0.15), transparent 70%);
          pointer-events: none;
          transform: translate(-50%, -50%);
          z-index: 0;
        }

        .contact-desc {
          color: var(--muted);
          margin: 0 auto 2rem;
          max-width: 520px;
          font-size: clamp(0.85rem, 1.3vw, 1rem);
          line-height: 1.7;
        }

        .contact-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
          gap: clamp(0.8rem, 2vw, 1.2rem);
          max-width: 900px;
          margin: 0 auto 2rem;
          position: relative;
          z-index: 1;
        }

        /* 🌈 Gradient Border Card */
        .contact-card {
          position: relative;
          padding: 1px;
          border-radius: var(--radius);
          background: linear-gradient(135deg, var(--accent), var(--accent2), transparent);
        }

        .contact-inner {
          background: var(--surface);
          border-radius: var(--radius);
          padding: clamp(1rem, 2.5vw, 1.4rem);
          display: flex;
          flex-direction: column;
          gap: 6px;
          text-align: left;
          transition: transform 0.25s ease, box-shadow 0.25s ease;
        }

        .contact-card:hover .contact-inner {
          transform: translateY(-6px) scale(1.03);
          box-shadow: 0 15px 40px rgba(0,0,0,0.25);
        }

        /* ✨ Floating Icon */
        .contact-icon {
          font-size: 1.3rem;
          animation: float 3s ease-in-out infinite;
        }

        @keyframes float {
          0%,100% { transform: translateY(0); }
          50% { transform: translateY(-6px); }
        }

        .contact-lbl {
          font-size: 0.7rem;
          color: var(--muted);
          font-weight: 700;
          letter-spacing: 0.1em;
          text-transform: uppercase;
        }

        .contact-val {
          font-size: clamp(0.8rem, 1.1vw, 0.9rem);
          color: var(--text);
          font-weight: 500;
          line-height: 1.5;
          word-break: break-word;
        }

        .contact-cta {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          background: linear-gradient(135deg, var(--accent), var(--accent2));
          color: #fff;
          padding: 12px 28px;
          border-radius: 99px;
          font-weight: 700;
          transition: transform 0.2s;
          text-decoration: none;
        }

        .contact-cta:hover {
          transform: scale(1.06);
        }

        .footer-txt {
          color: var(--muted);
          font-size: 0.8rem;
          margin-top: 3rem;
        }
      `}</style>

      <section className="contact-section" id="contact" ref={sectionRef}>
        <motion.div
          variants={container}
          initial="hidden"
          whileInView="show"
          viewport={{ once: true }}
        >
          <SectionLabel text="Contact" />

          <motion.h2 style={{ ...sectionTitle }} variants={fadeUp}>
            Let's Build Something
          </motion.h2>

          <motion.p className="contact-desc" variants={fadeUp}>
            Available for full-time roles and exciting fintech and enterprise
            projects. Let’s connect and build scalable, high-performance systems together.
          </motion.p>

          {/* 🔥 Cards */}
          <div className="contact-grid">
            {items.map((item, i) => {
              const ref = useRef();

              return (
                <motion.div
                  key={i}
                  className="contact-card"
                  variants={fadeUp}
                  ref={ref}
                  onMouseMove={(e) => handleMouseMove(e, ref)}
                  onMouseLeave={() => resetMagnet(ref)}
                  onClick={() => item.copy && handleCopy(item.value)}
                >
                  <div className="contact-inner">
                    <span className="contact-icon">{item.icon}</span>
                    <span className="contact-lbl">{item.label}</span>
                    <span className="contact-val">{item.value}</span>
                  </div>
                </motion.div>
              );
            })}
          </div>

          <motion.a
            href="mailto:chavanak870@gmail.com"
            className="contact-cta"
            variants={fadeUp}
            whileHover={{ scale: 1.08 }}
          >
            ✉ Send Email
          </motion.a>

          <div className="footer-txt">
            Built with React · Designed to impress · © {new Date().getFullYear()} Akash Chavan
          </div>
        </motion.div>
      </section>
    </>
  );
}
